def rule_based_spam_score(subject: str, body: str) -> float:
    """Explicit rules: no training data required."""
    score = 0.0
    text = f"{subject} {body}".lower()
    if "winner" in text and "click" in text:
        score += 0.6
    if text.count("!") >= 3:
        score += 0.2
    return min(score, 1.0)


