from collections import deque

GRID = [
    "S..#",
    ".#..",
    "..G.",
]

def bfs_shortest_path(grid):
    start = next((i, j) for i, row in enumerate(grid) for j, c in enumerate(row) if c == "S")
    goal = next((i, j) for i, row in enumerate(grid) for j, c in enumerate(row) if c == "G")
    queue = deque([(start, [])])
    seen = {start}
    moves = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    while queue:
        (r, c), path = queue.popleft()
        if (r, c) == goal:
            return path
        for dr, dc in moves:
            nr, nc = r + dr, c + dc
            if 0 <= nr < len(grid) and 0 <= nc < len(grid[0]) and grid[nr][nc] != "#":
                if (nr, nc) not in seen:
                    seen.add((nr, nc))
                    queue.append(((nr, nc), path + [(dr, dc)]))
    return None

print("steps:", len(bfs_shortest_path(GRID)))
